const input = $input.first().json;
const body = input.body || input;
const { token, vendor_id } = body;

// --- System token for scheduled sync ---
const SYSTEM_SYNC_SECRET = 'ks_sys_8f3a2b1c4d5e6f7a8b9c0d1e2f3a4b5c';
let isSystemSync = false;

// --- Constants ---
const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
const sbHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// --- Helper: Supabase request ---
async function sbFetch(path, options = {}) {
  const url = `${SUPABASE_URL}${path}`;
  const resp = await httpReq(url, {
    headers: { ...sbHeaders, ...(options.headers || {}) },
    method: options.method || 'GET',
    body: options.body ? JSON.stringify(options.body) : undefined
  });
  const text = await resp.text();
  if (!resp.ok) {
    throw new Error(`Supabase ${options.method || 'GET'} ${path} failed (${resp.status}): ${text}`);
  }
  return text ? JSON.parse(text) : null;
}

function safeStr(val, fallback = '') {
  if (val === null || val === undefined) return fallback;
  return String(val).trim() || fallback;
}

function safeFloat(val, fallback = 0) {
  const n = parseFloat(val);
  return isNaN(n) ? fallback : n;
}

function safeInt(val, fallback = 0) {
  const n = parseInt(val, 10);
  return isNaN(n) ? fallback : n;
}

// PrestaShop name can be a string or array of {id, value} for multilingual
function extractName(nameField) {
  if (!nameField) return '';
  if (typeof nameField === 'string') return nameField.trim();
  if (Array.isArray(nameField)) {
    // Prefer first language entry
    return safeStr(nameField[0]?.value || nameField[0]);
  }
  if (typeof nameField === 'object' && nameField.value) {
    return safeStr(nameField.value);
  }
  return String(nameField).trim();
}

// PrestaShop returns XML-like structures for some fields
function extractTextField(field) {
  if (!field) return '';
  if (typeof field === 'string') return field.trim();
  if (Array.isArray(field)) {
    const first = field[0];
    if (typeof first === 'object' && first?.value !== undefined) return safeStr(first.value);
    return safeStr(first);
  }
  if (typeof field === 'object' && field.value !== undefined) return safeStr(field.value);
  return '';
}

try {
  // ========== STEP 1: Verify token ==========
  if (!token || typeof token !== 'string') {
    return [{ json: { success: false, error: 'Missing or invalid token' } }];
  }
  if (!vendor_id) {
    return [{ json: { success: false, error: 'Missing vendor_id' } }];
  }

  let user_id = null;

  if (token === SYSTEM_SYNC_SECRET) {
    isSystemSync = true;
  } else {
    // Auth verification — call auth-verify endpoint
    const authResp = await httpReq('https://api.katalync.com/webhook/auth-verify', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ token })
    });
    const authData = await authResp.json();
    if (!authData.success) {
      return [{ json: { success: false, error: authData.error || 'Token invalid or expired' } }];
    }
    const userEmail = authData.email;

    // Upsert user into Supabase (auto-provision from n8n session data)
    const upsertData = await sbFetch('/users?on_conflict=email', {
      method: 'POST',
      headers: { 'Prefer': 'resolution=merge-duplicates,return=representation' },
      body: [{
        email: authData.email,
        name: authData.name || authData.email,
        password_hash: 'oauth-managed',
        role: authData.role || 'user',
        company: authData.company || null,
        lang: authData.lang || 'es',
        onboarded: authData.onboarded || false,
        subscription_status: authData.subscription_status || 'active',
        last_login_at: new Date().toISOString()
      }]
    });
    user_id = upsertData && upsertData.length > 0 ? upsertData[0].id : null;
    if (!user_id) {
      return [{ json: { success: false, error: 'Failed to provision user' } }];
    }
  }

  // ========== STEP 2: Fetch vendor ==========
  const vendorQuery = isSystemSync
    ? `/vendors?id=eq.${vendor_id}&select=*`
    : `/vendors?id=eq.${vendor_id}&user_id=eq.${user_id}&select=*`;
  const vendors = await sbFetch(vendorQuery);
  if (!vendors || vendors.length === 0) {
    return [{ json: { success: false, error: 'Vendor not found or access denied' } }];
  }
  const vendor = vendors[0];

  // ========== STEP 3: Validate source ==========
  if (vendor.source !== 'prestashop') {
    return [{ json: { success: false, error: `Vendor source is '${vendor.source}', expected 'prestashop'` } }];
  }
  if (!vendor.source_url || !vendor.source_api_key) {
    return [{ json: { success: false, error: 'Vendor missing source_url or source_api_key' } }];
  }

  const prestaUrl = vendor.source_url.replace(/\/+$/, '');
  // PrestaShop uses API key as username with empty password for Basic auth
  const authHeader = 'Basic ' + Buffer.from(`${vendor.source_api_key}:`).toString('base64');

  // ========== STEP 4: Create sync_log ==========
  const startedAt = new Date().toISOString();
  const syncLogs = await sbFetch('/sync_logs', {
    method: 'POST',
    body: {
      vendor_id: vendor.id,
      direction: 'pull',
      total_products: 0,
      created_count: 0,
      updated_count: 0,
      error_count: 0,
      status: 'running',
      started_at: startedAt
    }
  });
  const syncLog = syncLogs[0];
  const sync_log_id = syncLog.id;

  // ========== STEP 5-7: Fetch ALL PrestaShop products (with pagination) ==========
  let allProducts = [];
  const LIMIT = 50;
  let offset = 0;
  let pageCount = 0;
  const MAX_PAGES = 400; // Safety limit: 400 * 50 = 20,000 products
  let hasMore = true;

  while (hasMore && pageCount < MAX_PAGES) {
    pageCount++;
    let resp;
    try {
      const apiUrl = `${prestaUrl}/api/products?display=full&limit=${LIMIT}&offset=${offset}&output_format=JSON&filter[active]=[1]`;
      resp = await httpReq(apiUrl, {
        method: 'GET',
        headers: {
          'Authorization': authHeader,
          'Content-Type': 'application/json'
        }
      });
    } catch (fetchErr) {
      throw new Error(`PrestaShop API connection failed (page ${pageCount}): ${fetchErr.message}`);
    }

    if (!resp.ok) {
      const errText = await resp.text();
      // 404 at offset often means no more products
      if (resp.status === 404 && offset > 0) {
        hasMore = false;
        break;
      }
      throw new Error(`PrestaShop API error ${resp.status} (page ${pageCount}): ${errText.substring(0, 500)}`);
    }

    let data;
    try {
      data = await resp.json();
    } catch (jsonErr) {
      // PrestaShop sometimes returns XML despite output_format=JSON
      throw new Error(`PrestaShop returned non-JSON response at offset ${offset}. Ensure the Webservice is configured for JSON output.`);
    }

    // PrestaShop wraps products in { products: [...] }
    const products = data.products || data.product || [];
    const productList = Array.isArray(products) ? products : [products];

    if (productList.length === 0) {
      hasMore = false;
    } else {
      allProducts = allProducts.concat(productList);
      offset += LIMIT;

      // If we got fewer than LIMIT, there are no more
      if (productList.length < LIMIT) {
        hasMore = false;
      }
    }

    // Rate limiting
    if (hasMore) {
      await new Promise(resolve => setTimeout(resolve, 300));
    }
  }

  // ========== Fetch stock quantities ==========
  // PrestaShop separates stock from products in newer versions
  // Try to get stock_availables for accurate counts
  const stockMap = {}; // product_id → quantity
  try {
    let stockOffset = 0;
    let stockHasMore = true;
    let stockPages = 0;

    while (stockHasMore && stockPages < MAX_PAGES) {
      stockPages++;
      const stockResp = await httpReq(
        `${prestaUrl}/api/stock_availables?display=[id_product,quantity]&limit=${LIMIT}&offset=${stockOffset}&output_format=JSON`,
        {
          method: 'GET',
          headers: { 'Authorization': authHeader }
        }
      );

      if (stockResp.ok) {
        const stockData = await stockResp.json();
        const stocks = stockData.stock_availables || stockData.stock_available || [];
        const stockList = Array.isArray(stocks) ? stocks : [stocks];

        if (stockList.length === 0) {
          stockHasMore = false;
        } else {
          for (const s of stockList) {
            const pid = safeStr(s.id_product);
            if (pid) {
              // Sum quantities if multiple stock entries for same product (combos)
              stockMap[pid] = (stockMap[pid] || 0) + safeInt(s.quantity, 0);
            }
          }
          stockOffset += LIMIT;
          if (stockList.length < LIMIT) stockHasMore = false;
        }
      } else {
        // Stock API might not be enabled — fall back to product.quantity
        stockHasMore = false;
      }
      await new Promise(resolve => setTimeout(resolve, 200));
    }
  } catch (stockErr) {
    console.log('Warning: Could not fetch stock_availables, using product.quantity:', stockErr.message);
  }

  // ========== Map products to Katalync format ==========
  const mappedProducts = [];
  const syncErrors = [];

  for (const product of allProducts) {
    try {
      const productId = safeStr(product.id);
      let sku = safeStr(product.reference);
      if (!sku) sku = `ps-${productId}`;

      // Name: can be multilingual
      const name = extractName(product.name) || `Product ${productId}`;

      // EAN
      const ean = safeStr(product.ean13 || product.upc || product.isbn);

      // Brand / Manufacturer
      const brand = safeStr(product.manufacturer_name || extractTextField(product.manufacturer_name));

      // Category
      let category = '';
      if (product.category_default_name) {
        category = extractTextField(product.category_default_name);
      } else if (product.id_category_default) {
        category = `category-${product.id_category_default}`;
      }

      // Price: PrestaShop can return price with or without tax
      // price_tax_excl or just price
      let price = safeFloat(product.price);
      if (product.price_tax_incl) {
        price = safeFloat(product.price_tax_incl);
      }

      // Stock: prefer stock_availables data, fallback to product.quantity
      let stock = 0;
      if (stockMap[productId] !== undefined) {
        stock = stockMap[productId];
      } else {
        stock = safeInt(product.quantity, 0);
      }

      // Image URL: PrestaShop image API
      let imageUrl = '';
      if (product.id_default_image) {
        imageUrl = `${prestaUrl}/api/images/products/${productId}/${product.id_default_image}`;
      } else if (product.associations?.images && product.associations.images.length > 0) {
        const firstImageId = product.associations.images[0].id;
        imageUrl = `${prestaUrl}/api/images/products/${productId}/${firstImageId}`;
      } else {
        // Fallback: try first image
        imageUrl = `${prestaUrl}/api/images/products/${productId}/1`;
      }

      // Check for product combinations (variants)
      const combinations = product.associations?.combinations || [];

      if (combinations.length > 0) {
        // Fetch combinations for this product
        let fetchedCombinations = false;
        try {
          const combResp = await httpReq(
            `${prestaUrl}/api/combinations?filter[id_product]=${productId}&display=full&output_format=JSON`,
            {
              method: 'GET',
              headers: { 'Authorization': authHeader }
            }
          );

          if (combResp.ok) {
            const combData = await combResp.json();
            const combs = combData.combinations || combData.combination || [];
            const combList = Array.isArray(combs) ? combs : [combs];

            for (const comb of combList) {
              try {
                let combSku = safeStr(comb.reference || comb.supplier_reference);
                if (!combSku) combSku = `${sku}-c${comb.id}`;

                // Build combination name from option values
                let combName = name;
                if (comb.associations?.product_option_values) {
                  const optionValues = comb.associations.product_option_values
                    .map(ov => safeStr(ov.name || ov.id))
                    .filter(Boolean);
                  if (optionValues.length > 0) {
                    combName = `${name} - ${optionValues.join(' / ')}`;
                  }
                }

                const combMapped = {
                  vendor_id: vendor.id,
                  sku: combSku,
                  ean: safeStr(comb.ean13 || comb.upc || ean),
                  name: combName.substring(0, 500),
                  brand: brand,
                  category: category,
                  price: safeFloat(comb.price) > 0 ? price + safeFloat(comb.price) : price,
                  stock: safeInt(comb.quantity, 0),
                  image_url: imageUrl,
                  raw_data: {
                    prestashop_product_id: parseInt(productId),
                    prestashop_combination_id: parseInt(comb.id),
                    prestashop_type: 'combination',
                    prestashop_reference: product.reference,
                    prestashop_active: product.active,
                    prestashop_condition: product.condition,
                    combination_reference: comb.reference,
                    combination_weight: comb.weight,
                    combination_minimal_quantity: comb.minimal_quantity,
                    combination_price_impact: comb.price,
                    combination_default: comb.default_on
                  },
                  sync_status: 'synced',
                  last_synced_at: new Date().toISOString()
                };
                mappedProducts.push(combMapped);
              } catch (combErr) {
                syncErrors.push({
                  sync_log_id,
                  sku: `${sku}-c${comb.id}`,
                  field: 'combination_mapping',
                  error_type: 'mapping_error',
                  message: `Error mapping combination ${comb.id}: ${combErr.message}`
                });
              }
            }
            fetchedCombinations = true;
          }
        } catch (combFetchErr) {
          console.log(`Warning: Failed to fetch combinations for product ${productId}:`, combFetchErr.message);
        }

        // If we successfully fetched combinations, skip the base product
        if (fetchedCombinations) continue;
      }

      // Map simple product (or product whose combinations failed to fetch)
      const mapped = {
        vendor_id: vendor.id,
        sku: sku,
        ean: ean,
        name: name.substring(0, 500),
        brand: brand,
        category: category,
        price: price,
        stock: stock,
        image_url: imageUrl,
        raw_data: {
          prestashop_product_id: parseInt(productId),
          prestashop_type: 'simple',
          prestashop_reference: product.reference,
          prestashop_active: product.active,
          prestashop_condition: product.condition,
          prestashop_visibility: product.visibility,
          prestashop_weight: product.weight,
          prestashop_width: product.width,
          prestashop_height: product.height,
          prestashop_depth: product.depth,
          prestashop_tax_id: product.id_tax_rules_group,
          prestashop_supplier: product.id_supplier,
          prestashop_date_add: product.date_add,
          prestashop_date_upd: product.date_upd,
          meta_title: extractTextField(product.meta_title),
          description_short: extractTextField(product.description_short)?.substring(0, 500)
        },
        sync_status: 'synced',
        last_synced_at: new Date().toISOString()
      };
      mappedProducts.push(mapped);

    } catch (productErr) {
      syncErrors.push({
        sync_log_id,
        sku: safeStr(product.reference || product.id),
        field: 'product_mapping',
        error_type: 'mapping_error',
        message: `Error mapping product ${product.id}: ${productErr.message}`
      });
    }

    // Small delay between products with combinations
    await new Promise(resolve => setTimeout(resolve, 50));
  }

  // ========== STEP 8: Delta sync + Upsert products ==========
  let createdCount = 0;
  let updatedCount = 0;
  let unchangedCount = 0;
  let errorCount = syncErrors.length;
  const BATCH_SIZE = 50;

  // Fetch existing products with comparison fields
  const existingProducts = await sbFetch(
    `/vendor_products?vendor_id=eq.${vendor.id}&select=sku,name,brand,category,price,stock,image_url,ean&limit=100000`
  );
  const existingMap = {};
  (existingProducts || []).forEach(p => { existingMap[p.sku] = p; });
  const existingSkus = new Set(Object.keys(existingMap));

  // Compare each product and set sync_status
  for (const mapped of mappedProducts) {
    const existing = existingMap[mapped.sku];
    if (!existing) {
      mapped.sync_status = 'new';
    } else {
      const changed = (
        mapped.name !== (existing.name || '') ||
        mapped.brand !== (existing.brand || '') ||
        mapped.category !== (existing.category || '') ||
        Math.round(mapped.price * 100) !== Math.round((existing.price || 0) * 100) ||
        mapped.stock !== (existing.stock || 0) ||
        mapped.image_url !== (existing.image_url || '') ||
        mapped.ean !== (existing.ean || '')
      );
      if (changed) {
        mapped.sync_status = 'changed';
        mapped.sprinter_product = null;
        mapped.sprinter_offer = null;
      } else {
        mapped.sync_status = 'unchanged';
        unchangedCount++;
      }
    }
  }

  // Only upsert new or changed products
  const productsToUpsert = mappedProducts.filter(p => p.sync_status !== 'unchanged');

  // Upsert in batches
  for (let i = 0; i < productsToUpsert.length; i += BATCH_SIZE) {
    const batch = productsToUpsert.slice(i, i + BATCH_SIZE);

    try {
      await sbFetch('/vendor_products', {
        method: 'POST',
        headers: {
          'Prefer': 'resolution=merge-duplicates,return=representation'
        },
        body: batch
      });

      for (const item of batch) {
        if (existingSkus.has(item.sku)) {
          updatedCount++;
        } else {
          createdCount++;
        }
      }
    } catch (upsertErr) {
      // Fallback: individual inserts
      for (const item of batch) {
        try {
          await sbFetch('/vendor_products', {
            method: 'POST',
            headers: {
              'Prefer': 'resolution=merge-duplicates,return=representation'
            },
            body: [item]
          });
          if (existingSkus.has(item.sku)) {
            updatedCount++;
          } else {
            createdCount++;
          }
        } catch (itemErr) {
          errorCount++;
          syncErrors.push({
            sync_log_id,
            sku: item.sku,
            field: 'upsert',
            error_type: 'database_error',
            message: `Upsert failed: ${itemErr.message}`.substring(0, 500)
          });
        }
      }
    }
  }

  // ========== STEP 9: Update sync_log ==========
  const completedAt = new Date().toISOString();
  await sbFetch(`/sync_logs?id=eq.${sync_log_id}`, {
    method: 'PATCH',
    body: {
      status: errorCount > 0 ? 'completed_with_errors' : 'completed',
      total_products: mappedProducts.length,
      created_count: createdCount,
      updated_count: updatedCount,
      error_count: errorCount,
      error_details: syncErrors.length > 0 ? syncErrors.slice(0, 100) : null,
      completed_at: completedAt
    }
  });

  // ========== STEP 10: Update vendor ==========
  const syncInterval = vendor.sync_interval_hours || 24;
  const nextSyncAt = new Date(Date.now() + syncInterval * 60 * 60 * 1000).toISOString();

  await sbFetch(`/vendors?id=eq.${vendor.id}`, {
    method: 'PATCH',
    body: {
      product_count: createdCount + updatedCount,
      sync_status: errorCount > 0 ? 'completed_with_errors' : 'synced',
      last_sync_at: completedAt,
      next_sync_at: nextSyncAt,
      last_sync_products_synced: createdCount + updatedCount,
      last_sync_errors: errorCount
    }
  });

  // ========== STEP 11: Insert sync_errors ==========
  if (syncErrors.length > 0) {
    for (let i = 0; i < syncErrors.length; i += BATCH_SIZE) {
      const errorBatch = syncErrors.slice(i, i + BATCH_SIZE);
      try {
        await sbFetch('/sync_errors', {
          method: 'POST',
          body: errorBatch
        });
      } catch (e) {
        console.log('Warning: Failed to log sync errors batch:', e.message);
      }
    }
  }


  // Trigger auto-convert after sync (fire-and-forget)
  if (productsToUpsert.length > 0) {
    httpReq('https://api.katalync.com/webhook/auto-convert', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        token: isSystemSync ? SYSTEM_SYNC_SECRET : token,
        vendor_id: vendor.id,
        marketplaces: (vendor.config && vendor.config.marketplaces) || ['sprinter_es']
      }),
      timeout: 5000
    }).catch(() => {});
  }

  // ========== STEP 12: Return result ==========
  return [{
    json: {
      success: true,
      vendor_id: vendor.id,
      vendor_name: vendor.name,
      source: 'prestashop',
      total: mappedProducts.length,
      created: createdCount,
      updated: updatedCount,
      errors: errorCount,
      pages_fetched: pageCount,
      presta_products: allProducts.length,
      stock_entries_loaded: Object.keys(stockMap).length,
      sync_log_id: sync_log_id,
      duration_ms: Date.now() - new Date(startedAt).getTime()
    }
  }];

} catch (fatalError) {
  // Fatal error handler
  try {
    if (typeof sync_log_id !== 'undefined') {
      await sbFetch(`/sync_logs?id=eq.${sync_log_id}`, {
        method: 'PATCH',
        body: {
          status: 'failed',
          error_details: [{ error: fatalError.message }],
          completed_at: new Date().toISOString()
        }
      });
    }
    if (typeof vendor !== 'undefined') {
      await sbFetch(`/vendors?id=eq.${vendor.id}`, {
        method: 'PATCH',
        body: {
          sync_status: 'error'
        }
      });
    }
  } catch (e) {
    // Best effort
  }

  return [{
    json: {
      success: false,
      error: fatalError.message,
      vendor_id: body.vendor_id || null
    }
  }];
}
